const IMGS = {
  logo: "data:image/png;base64,",
  jollof: "data:image/jpeg;base64,",
  fried: "data:image/jpeg;base64,",
  noodles: "data:image/jpeg;base64,",
  banku: "data:image/jpeg;base64,",
  extras: "data:image/jpeg;base64,",
  drinks: "data:image/jpeg;base64,",
};

