const MENU=[
  {id:1,cat:"jollof",name:"Jollof + Drumstick",desc:"Smoky party jollof with crispy drumstick",price:55,img:"jollof",pop:true},
  {id:2,cat:"jollof",name:"Jollof + Chicken Thigh",desc:"Tender thigh with signature jollof",price:70,img:"jollof"},
  {id:3,cat:"jollof",name:"Beef Jollof",desc:"Slow-cooked beef, rich jollof",price:65,img:"jollof"},
  {id:4,cat:"jollof",name:"Jollof + Tilapia",desc:"Whole grilled tilapia with jollof",price:90,img:"jollof"},
  {id:5,cat:"jollof",name:"Jollof + Goat Meat",desc:"Premium goat, bold flavour",price:100,img:"jollof",badge:"Premium"},
  {id:6,cat:"jollof",name:"Jollof + Sauce",desc:"Beef or chicken sauce combo",price:75,img:"jollof"},
  {id:7,cat:"fried",name:"Vegetable Fried Rice",desc:"Light wholesome veggie rice",price:30,img:"fried"},
  {id:8,cat:"fried",name:"Shredded Chicken/Beef Rice",desc:"Tender shredded protein tossed through",price:40,img:"fried"},
  {id:9,cat:"fried",name:"Fried Rice + Drumstick",desc:"Classic crowd-pleaser combo",price:55,img:"fried",pop:true},
  {id:10,cat:"fried",name:"Fried Rice + Chicken Thigh",desc:"Juicy thigh on wok-tossed rice",price:70,img:"fried"},
  {id:11,cat:"fried",name:"Fried Rice + Sauce",desc:"Beef or chicken sauce",price:75,img:"fried"},
  {id:12,cat:"fried",name:"Fried Rice + Tilapia",desc:"Whole grilled tilapia",price:90,img:"fried"},
  {id:13,cat:"fried",name:"Fried Rice + Goat Meat",desc:"Rich goat on perfect fried rice",price:100,img:"fried",badge:"Premium"},
  {id:14,cat:"fried",name:"Assorted Fried Rice",desc:"Mixed proteins — full experience",price:70,img:"fried"},
  {id:15,cat:"noodles",name:"Noodles + Sausage",desc:"Classic sausage noodles",price:35,img:"noodles"},
  {id:16,cat:"noodles",name:"Noodles + Egg",desc:"Topped with fried egg",price:40,img:"noodles"},
  {id:17,cat:"noodles",name:"Noodles + Drumstick",desc:"Sausage noodles with drumstick",price:55,img:"noodles"},
  {id:18,cat:"noodles",name:"Noodles + Chicken Thigh",desc:"Generous thigh, bold noodle bowl",price:70,img:"noodles",pop:true},
  {id:19,cat:"noodles",name:"Assorted Noodles",desc:"Mixed protein noodle bowl",price:60,img:"noodles"},
  {id:20,cat:"banku",name:"Banku + Tilapia",desc:"Fermented corn dough, grilled tilapia, shito & pepper",price:80,img:"banku",badge:"Local Fav"},
  {id:21,cat:"snacks",name:"Meat Pie",desc:"Flaky pastry, minced meat",price:12,img:"extras"},
  {id:22,cat:"snacks",name:"Chicken Pie",desc:"Golden pastry, spiced chicken",price:12,img:"extras"},
  {id:23,cat:"snacks",name:"Fish Roll",desc:"Crispy roll, seasoned fish",price:12,img:"extras"},
  {id:24,cat:"snacks",name:"Puff Puff",desc:"Soft fluffy dough balls",price:7,img:"extras"},
  {id:25,cat:"snacks",name:"Chin Chin",desc:"Crunchy fried snack",price:7,img:"extras"},
  {id:26,cat:"extras",name:"Coleslaw",desc:"Fresh creamy coleslaw",price:5,img:"extras"},
  {id:27,cat:"extras",name:"Extra Banku",desc:"Additional banku ball",price:5,img:"extras"},
  {id:28,cat:"extras",name:"Shito",desc:"Ghanaian black pepper sauce",price:3,img:"extras"},
  {id:29,cat:"extras",name:"Jollof Only",desc:"Plain jollof, no protein",price:30,img:"jollof"},
  {id:30,cat:"extras",name:"Kelewele",desc:"Spiced fried plantain",price:15,img:"extras"},
  {id:31,cat:"drinks",name:"Can Malt",desc:"Smooth malt drink",price:16,img:"drinks"},
  {id:32,cat:"drinks",name:"B.B Cocktail",desc:"Fruity cocktail can",price:15,img:"drinks"},
  {id:33,cat:"drinks",name:"Alvaro",desc:"Classic pear drink",price:15,img:"drinks"},
  {id:34,cat:"drinks",name:"Can Coke",desc:"Ice cold Coca-Cola",price:12,img:"drinks"},
  {id:35,cat:"drinks",name:"Can Fanta",desc:"Refreshing orange Fanta",price:12,img:"drinks"},
  {id:36,cat:"drinks",name:"Bottled Coke",desc:"500ml Coca-Cola",price:15,img:"drinks"},
  {id:37,cat:"drinks",name:"Ceres Juice",desc:"Premium fruit juice",price:45,img:"drinks"},
  {id:38,cat:"drinks",name:"Don Simon",desc:"Multifruits juice",price:38,img:"drinks"},
  {id:39,cat:"drinks",name:"Fruteli",desc:"Natural all-fruit juice",price:32,img:"drinks"},
  {id:40,cat:"drinks",name:"Sobolo",desc:"Refreshing hibiscus drink",price:10,img:"drinks"},
  {id:41,cat:"drinks",name:"Magic Blendz",desc:"Special blended drink",price:12,img:"drinks"},
  {id:42,cat:"drinks",name:"Bottled Water",desc:"Pure chilled water",price:5,img:"drinks"},
];

const CATS=[
  {id:"all",label:"All",icon:"⊞"},
  {id:"jollof",label:"Jollof",icon:"🔥"},
  {id:"fried",label:"Fried Rice",icon:"🍛"},
  {id:"noodles",label:"Noodles",icon:"🍜"},
  {id:"banku",label:"Banku",icon:"🐟"},
  {id:"snacks",label:"Snacks",icon:"🥐"},
  {id:"extras",label:"Extras",icon:"✨"},
  {id:"drinks",label:"Drinks",icon:"🥤"},
];

export default function App() {
  const [tab,setTab]=useState("home");
  const [cart,setCart]=useState([]);
  const [detail,setDetail]=useState(null);
  const [cat,setCat]=useState("all");
  const [q,setQ]=useState("");
  const [toast,setToast]=useState(null);
  const [mode,setMode]=useState("delivery");
  const [pay,setPay]=useState("MTN MoMo");
  const [form,setForm]=useState({name:"",phone:"",address:"",notes:""});
  const [spice,setSpice]=useState("Medium");
  const [done,setDone]=useState(false);

  const total=cart.reduce((s,i)=>s+i.price*i.qty,0);
  const count=cart.reduce((s,i)=>s+i.qty,0);

  const toast_=(m)=>{setToast(m);setTimeout(()=>setToast(null),2200);};

  const addToCart=(item,sp)=>{
    const lv=sp||spice;
    setCart(p=>{
      const i=p.findIndex(x=>x.id===item.id&&x.spice===lv);
      if(i>=0){const n=[...p];n[i]={...n[i],qty:n[i].qty+1};return n;}
      return [...p,{...item,qty:1,spice:lv}];
    });
    toast_("Added to cart! 🎉");
  };

  const chQty=(id,sp,d)=>setCart(p=>p.map(i=>i.id===id&&i.spice===sp?{...i,qty:i.qty+d}:i).filter(i=>i.qty>0));

  const filtered=MENU.filter(i=>(cat==="all"||i.cat===cat)&&(!q||i.name.toLowerCase().includes(q.toLowerCase())||i.desc.toLowerCase().includes(q.toLowerCase())));

  const submitOrder=()=>{
    if(!form.name||!form.phone){toast_("Fill name & phone first");return;}
    const lines=cart.map(i=>`${i.name} x${i.qty} = GH₵${i.price*i.qty} (${i.spice})`).join("%0A");
    const addr=mode==="delivery"?`%0AAddress: ${form.address}`:"";
    const msg=`New Order – Tasty Chef%0A%0AName: ${form.name}%0APhone: ${form.phone}%0AType: ${mode==="delivery"?"Delivery":"Pickup"}${addr}%0A%0AItems:%0A${lines}%0A%0ATotal: GH₵${total}%0APayment: ${pay}${form.notes?"%0ANotes: "+form.notes:""}`;
    window.open(`https://wa.me/233205218123?text=${msg}`,"_blank");
    setDone(true);setCart([]);
    setTimeout(()=>{setDone(false);setTab("home");},3000);
  };

  if(detail) return <Detail item={detail} onBack={()=>setDetail(null)} onAdd={addToCart} cart={cart} chQty={chQty} spice={spice} setSpice={setSpice}/>;

  return(
    <div style={{fontFamily:"'Inter',system-ui,sans-serif",background:"#fafafa",maxWidth:430,margin:"0 auto",minHeight:"100vh",display:"flex",flexDirection:"column",position:"relative"}}>
      <style>{`
        *{box-sizing:border-box;-webkit-tap-highlight-color:transparent}
        ::-webkit-scrollbar{display:none}
        .sx{display:flex;gap:10px;overflow-x:auto;scrollbar-width:none}
        .tap:active{transform:scale(0.96);transition:transform 0.1s}
        input,textarea{outline:none;font-family:inherit}
        a{text-decoration:none}
      `}</style>

      {toast&&<div style={{position:"fixed",bottom:90,left:"50%",transform:"translateX(-50%)",background:BK,color:WH,padding:"9px 20px",borderRadius:100,fontSize:13,fontWeight:700,zIndex:999,whiteSpace:"nowrap",boxShadow:"0 4px 20px rgba(0,0,0,.25)"}}>{toast}</div>}

      {done&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,.7)",zIndex:900,display:"flex",alignItems:"center",justifyContent:"center",padding:24}}>
        <div style={{background:WH,borderRadius:28,padding:36,textAlign:"center",maxWidth:280}}>
          <div style={{width:72,height:72,background:"#dcfce7",borderRadius:"50%",display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 16px",fontSize:36}}>✓</div>
          <div style={{fontSize:20,fontWeight:900,marginBottom:8}}>Order Sent! 🎉</div>
          <div style={{color:MT,fontSize:14,lineHeight:1.5}}>Check WhatsApp to confirm with Tasty Chef</div>
        </div>
      </div>}

      {/* HOME */}
      {tab==="home"&&<>
        <div style={{background:WH,padding:"14px 18px 10px",display:"flex",alignItems:"center",justifyContent:"space-between",borderBottom:`1px solid ${G2}`,position:"sticky",top:0,zIndex:50}}>
          <div>
            <div style={{fontSize:11,color:MT,fontWeight:600,letterSpacing:".05em",textTransform:"uppercase"}}>Welcome back 👋</div>
            <div style={{fontSize:18,fontWeight:900,color:BK}}>Tasty Chef</div>
          </div>
          <img src={IMGS.logo} alt="logo" style={{height:46,objectFit:"contain"}}/>
        </div>
        <div style={{flex:1,overflowY:"auto",paddingBottom:80}}>
          {/* HERO */}
          <div style={{background:`linear-gradient(150deg,${BK} 0%,#1c1c2e 100%)`,padding:"24px 18px 20px",position:"relative",overflow:"hidden"}}>
            <div style={{position:"absolute",top:-40,right:-40,width:160,height:160,borderRadius:"50%",background:"rgba(232,23,106,.1)"}}/>
            <div style={{color:"rgba(255,255,255,.5)",fontSize:11,fontWeight:700,letterSpacing:".08em",textTransform:"uppercase",marginBottom:8}}>Fresh · Fast · Tasty</div>
            <div style={{color:WH,fontSize:24,fontWeight:900,lineHeight:1.2,marginBottom:4}}>Bold Ghanaian<br/>flavours, <span style={{color:P}}>delivered.</span></div>
            <div style={{display:"flex",gap:8,marginTop:16}}>
              {[["🕐","12–9 PM","Mon–Sun"],["📍","Pickup","Available"],["⭐","20+","Menu Items"]].map(([ic,t,s])=>(
                <div key={t} style={{background:"rgba(255,255,255,.08)",borderRadius:12,padding:"9px 10px",flex:1,minWidth:0}}>
                  <div style={{fontSize:15,marginBottom:3}}>{ic}</div>
                  <div style={{color:WH,fontSize:12,fontWeight:700,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{t}</div>
                  <div style={{color:"rgba(255,255,255,.4)",fontSize:10}}>{s}</div>
                </div>
              ))}
            </div>
            <img src={IMGS.jollof} alt="food" style={{width:"100%",height:185,objectFit:"cover",borderRadius:18,marginTop:18,boxShadow:"0 16px 40px rgba(0,0,0,.5)"}}/>
          </div>

          {/* CATEGORIES */}
          <div style={{padding:"22px 0 0"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"0 18px",marginBottom:14}}>
              <div style={{fontSize:16,fontWeight:800,color:BK}}>Categories</div>
              <button onClick={()=>setTab("menu")} style={{background:"none",border:"none",color:P,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>See all →</button>
            </div>
            <div className="sx" style={{padding:"0 18px"}}>
              {[["jollof","Jollof","jollof"],["fried","Fried Rice","fried"],["noodles","Noodles","noodles"],["banku","Banku","banku"],["extras","Extras","extras"],["drinks","Drinks","drinks"]].map(([c,l,imgk])=>(
                <div key={c} onClick={()=>{setCat(c);setTab("menu");}} className="tap" style={{display:"flex",flexDirection:"column",alignItems:"center",gap:7,cursor:"pointer",flexShrink:0}}>
                  <div style={{width:68,height:68,borderRadius:18,overflow:"hidden",border:`2px solid ${G2}`}}>
                    <img src={IMGS[imgk]} alt={l} style={{width:"100%",height:"100%",objectFit:"cover"}}/>
                  </div>
                  <div style={{fontSize:11,fontWeight:700,color:BK}}>{l}</div>
                </div>
              ))}
            </div>
          </div>

          {/* FAN FAVS */}
          <div style={{padding:"24px 0 0"}}>
            <div style={{padding:"0 18px",marginBottom:14}}>
              <div style={{fontSize:16,fontWeight:800,color:BK}}>⭐ Fan Favourites</div>
            </div>
            <div className="sx" style={{padding:"0 18px"}}>
              {MENU.filter(i=>i.pop).map(item=>(
                <div key={item.id} className="tap" onClick={()=>setDetail(item)} style={{background:WH,borderRadius:20,overflow:"hidden",border:`1px solid ${G2}`,minWidth:165,flexShrink:0,cursor:"pointer"}}>
                  <img src={IMGS[item.img]} alt={item.name} style={{width:"100%",height:125,objectFit:"cover"}}/>
                  <div style={{padding:"11px 12px"}}>
                    <div style={{fontSize:13,fontWeight:700,color:BK,marginBottom:6,lineHeight:1.3}}>{item.name}</div>
                    <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}>
                      <span style={{fontSize:14,fontWeight:900,color:P}}>GH₵{item.price}</span>
                      <button className="tap" style={{width:32,height:32,borderRadius:"50%",background:P,border:"none",color:WH,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,fontWeight:300}} onClick={e=>{e.stopPropagation();addToCart(item);}}>+</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* QUICK ORDER */}
          <div style={{padding:"24px 18px 8px"}}>
            <div style={{fontSize:16,fontWeight:800,color:BK,marginBottom:14}}>🔥 Quick Order</div>
            {MENU.slice(0,5).map(item=>{
              const ci=cart.find(i=>i.id===item.id);
              return(
                <div key={item.id} className="tap" onClick={()=>setDetail(item)} style={{display:"flex",gap:12,alignItems:"center",background:WH,borderRadius:16,padding:"12px",border:`1px solid ${G2}`,marginBottom:10,cursor:"pointer"}}>
                  <img src={IMGS[item.img]} alt={item.name} style={{width:60,height:60,borderRadius:12,objectFit:"cover",flexShrink:0}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:14,fontWeight:700,color:BK,lineHeight:1.3}}>{item.name}</div>
                    <div style={{fontSize:12,color:MT,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",marginTop:2}}>{item.desc}</div>
                    <div style={{fontSize:14,fontWeight:900,color:P,marginTop:5}}>GH₵{item.price}</div>
                  </div>
                  {ci?(
                    <div style={{display:"flex",alignItems:"center",gap:6}}>
                      <button onClick={e=>{e.stopPropagation();chQty(item.id,ci.spice,-1);}} style={{width:26,height:26,borderRadius:"50%",border:`1px solid ${G2}`,background:"none",cursor:"pointer",fontWeight:800,fontSize:15,display:"flex",alignItems:"center",justifyContent:"center"}}>−</button>
                      <span style={{fontWeight:800,minWidth:16,textAlign:"center"}}>{ci.qty}</span>
                      <button onClick={e=>{e.stopPropagation();chQty(item.id,ci.spice,1);}} style={{width:26,height:26,borderRadius:"50%",background:P,border:"none",color:WH,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15}}>+</button>
                    </div>
                  ):(
                    <button className="tap" style={{width:34,height:34,borderRadius:"50%",background:P,border:"none",color:WH,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,fontWeight:300,flexShrink:0}} onClick={e=>{e.stopPropagation();addToCart(item);}}>+</button>
                  )}
                </div>
              );
            })}
            <button onClick={()=>setTab("menu")} className="tap" style={{width:"100%",padding:"14px",borderRadius:14,border:"none",background:BK,color:WH,fontSize:15,fontWeight:800,fontFamily:"inherit",cursor:"pointer",marginTop:4,marginBottom:12}}>Browse Full Menu</button>
          </div>
        </div>
      </>}

      {/* MENU */}
      {tab==="menu"&&<>
        <div style={{background:WH,padding:"14px 18px 10px",display:"flex",alignItems:"center",justifyContent:"space-between",borderBottom:`1px solid ${G2}`,position:"sticky",top:0,zIndex:50}}>
          <div style={{fontSize:18,fontWeight:900,color:BK}}>Menu</div>
          <button onClick={()=>setTab("cart")} style={{position:"relative",width:40,height:40,borderRadius:"50%",background:G1,border:"none",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20}}>
            🛒{count>0&&<div style={{position:"absolute",top:-2,right:-2,background:P,color:WH,borderRadius:"50%",width:18,height:18,fontSize:10,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center",border:"2px solid white"}}>{count}</div>}
          </button>
        </div>
        <div style={{flex:1,overflowY:"auto",paddingBottom:80}}>
          <div style={{padding:"14px 18px 0"}}>
            <div style={{background:G1,borderRadius:14,padding:"11px 14px",display:"flex",gap:10,alignItems:"center"}}>
              <span style={{fontSize:18,color:MT}}>🔍</span>
              <input value={q} onChange={e=>setQ(e.target.value)} placeholder="Search meals..." style={{border:"none",background:"none",fontSize:14,flex:1,color:BK}}/>
              {q&&<button onClick={()=>setQ("")} style={{background:"none",border:"none",cursor:"pointer",color:MT,fontSize:18,padding:0}}>✕</button>}
            </div>
          </div>
          <div className="sx" style={{padding:"12px 18px 0"}}>
            {CATS.map(c=>(
              <button key={c.id} onClick={()=>setCat(c.id)} className="tap" style={{padding:"8px 14px",borderRadius:100,border:`1.5px solid ${cat===c.id?P:G2}`,background:cat===c.id?P:WH,color:cat===c.id?WH:MT,fontSize:13,fontWeight:700,cursor:"pointer",whiteSpace:"nowrap",fontFamily:"inherit",flexShrink:0}}>
                {c.icon} {c.label}
              </button>
            ))}
          </div>
          <div style={{padding:"14px 18px"}}>
            {filtered.length===0?(
              <div style={{textAlign:"center",padding:"40px 0",color:MT}}>
                <div style={{fontSize:40,marginBottom:12}}>🍽️</div>
                <div style={{fontWeight:700,color:BK,fontSize:15}}>Nothing found</div>
              </div>
            ):filtered.map(item=>{
              const ci=cart.find(i=>i.id===item.id);
              return(
                <div key={item.id} className="tap" onClick={()=>setDetail(item)} style={{display:"flex",gap:12,alignItems:"center",background:WH,borderRadius:16,padding:"12px",border:`1px solid ${G2}`,marginBottom:10,cursor:"pointer"}}>
                  <img src={IMGS[item.img]} alt={item.name} style={{width:72,height:72,borderRadius:14,objectFit:"cover",flexShrink:0}}/>
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2}}>
                      <span style={{fontSize:14,fontWeight:700,color:BK,lineHeight:1.3}}>{item.name}</span>
                      {item.badge&&<span style={{background:P,color:WH,fontSize:9,fontWeight:700,padding:"2px 6px",borderRadius:100,flexShrink:0}}>{item.badge}</span>}
                      {item.pop&&<span style={{background:"#fff0f3",color:P,fontSize:9,fontWeight:700,padding:"2px 6px",borderRadius:100,flexShrink:0}}>Popular</span>}
                    </div>
                    <div style={{fontSize:12,color:MT,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.desc}</div>
                    <div style={{fontSize:15,fontWeight:900,color:P,marginTop:5}}>GH₵{item.price}</div>
                  </div>
                  {ci?(
                    <div style={{display:"flex",alignItems:"center",gap:6,flexShrink:0}}>
                      <button onClick={e=>{e.stopPropagation();chQty(item.id,ci.spice,-1);}} style={{width:28,height:28,borderRadius:"50%",border:`1px solid ${G2}`,background:"none",cursor:"pointer",fontWeight:800,fontSize:15,display:"flex",alignItems:"center",justifyContent:"center"}}>−</button>
                      <span style={{fontWeight:800,minWidth:16,textAlign:"center"}}>{ci.qty}</span>
                      <button onClick={e=>{e.stopPropagation();chQty(item.id,ci.spice,1);}} style={{width:28,height:28,borderRadius:"50%",background:P,border:"none",color:WH,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14}}>+</button>
                    </div>
                  ):(
                    <button className="tap" style={{width:34,height:34,borderRadius:"50%",background:P,border:"none",color:WH,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,fontWeight:300,flexShrink:0}} onClick={e=>{e.stopPropagation();addToCart(item);}}>+</button>
                  )}
                </div>
              );
            })}
          </div>
        </div>
      </>}

      {/* CART */}
      {tab==="cart"&&<>
        <div style={{background:WH,padding:"14px 18px 10px",display:"flex",alignItems:"center",justifyContent:"space-between",borderBottom:`1px solid ${G2}`,position:"sticky",top:0,zIndex:50}}>
          <div style={{fontSize:18,fontWeight:900,color:BK}}>Your Order</div>
          <div style={{fontSize:13,color:MT,fontWeight:600}}>{count} items</div>
        </div>
        <div style={{flex:1,overflowY:"auto",paddingBottom:80}}>
          {cart.length===0?(
            <div style={{textAlign:"center",padding:"60px 24px"}}>
              <div style={{fontSize:56,marginBottom:16}}>🛒</div>
              <div style={{fontSize:18,fontWeight:900,marginBottom:8}}>Cart is empty</div>
              <div style={{color:MT,marginBottom:24,fontSize:14}}>Add some delicious meals!</div>
              <button onClick={()=>setTab("menu")} style={{padding:"14px 32px",borderRadius:14,border:"none",background:P,color:WH,fontSize:15,fontWeight:800,cursor:"pointer",fontFamily:"inherit"}}>Browse Menu</button>
            </div>
          ):(
            <div style={{padding:"16px 18px"}}>
              {/* DELIVERY TOGGLE */}
              <div style={{background:G1,borderRadius:14,padding:4,display:"flex",marginBottom:20}}>
                {["delivery","pickup"].map(m=>(
                  <button key={m} onClick={()=>setMode(m)} className="tap" style={{flex:1,padding:"10px",borderRadius:10,border:"none",background:mode===m?WH:"transparent",color:mode===m?BK:MT,fontWeight:700,fontSize:13,cursor:"pointer",fontFamily:"inherit",boxShadow:mode===m?"0 2px 8px rgba(0,0,0,.08)":"none",display:"flex",alignItems:"center",justifyContent:"center",gap:6}}>
                    {m==="delivery"?"🚗":"📍"} {m==="delivery"?"Delivery":"Pickup"}
                  </button>
                ))}
              </div>

              {/* ITEMS */}
              <div style={{marginBottom:20}}>
                {cart.map(item=>(
                  <div key={item.id+item.spice} style={{display:"flex",gap:12,alignItems:"center",padding:"12px 0",borderBottom:`1px solid ${G2}`}}>
                    <img src={IMGS[item.img]} alt={item.name} style={{width:56,height:56,borderRadius:12,objectFit:"cover",flexShrink:0}}/>
                    <div style={{flex:1,minWidth:0}}>
                      <div style={{fontSize:14,fontWeight:700,color:BK}}>{item.name}</div>
                      <div style={{fontSize:12,color:MT}}>🌶 {item.spice}</div>
                      <div style={{fontSize:14,fontWeight:900,color:P,marginTop:2}}>GH₵{item.price*item.qty}</div>
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:8}}>
                      <button onClick={()=>chQty(item.id,item.spice,-1)} style={{width:28,height:28,borderRadius:"50%",border:`1.5px solid ${G2}`,background:"none",cursor:"pointer",fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center",fontSize:15}}>−</button>
                      <span style={{fontWeight:800,minWidth:18,textAlign:"center"}}>{item.qty}</span>
                      <button onClick={()=>chQty(item.id,item.spice,1)} style={{width:28,height:28,borderRadius:"50%",background:P,border:"none",color:WH,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14}}>+</button>
                    </div>
                  </div>
                ))}
              </div>

              {/* FORM */}
              <div style={{marginBottom:20}}>
                <div style={{fontSize:15,fontWeight:800,marginBottom:14}}>Your Details</div>
                {[["name","Full Name","Kwame Asante"],["phone","Phone Number","020 XXX XXXX"]].map(([k,l,p])=>(
                  <div key={k} style={{marginBottom:12}}>
                    <label style={{fontSize:12,fontWeight:600,color:MT,display:"block",marginBottom:5}}>{l}</label>
                    <input value={form[k]} onChange={e=>setForm({...form,[k]:e.target.value})} placeholder={p} style={{width:"100%",background:G1,border:`1.5px solid transparent`,borderRadius:12,padding:"12px 14px",fontSize:14}} onFocus={e=>e.target.style.borderColor=P} onBlur={e=>e.target.style.borderColor="transparent"}/>
                  </div>
                ))}
                {mode==="delivery"&&(
                  <div style={{marginBottom:12}}>
                    <label style={{fontSize:12,fontWeight:600,color:MT,display:"block",marginBottom:5}}>Delivery Address</label>
                    <input value={form.address} onChange={e=>setForm({...form,address:e.target.value})} placeholder="Your full address..." style={{width:"100%",background:G1,border:"1.5px solid transparent",borderRadius:12,padding:"12px 14px",fontSize:14}} onFocus={e=>e.target.style.borderColor=P} onBlur={e=>e.target.style.borderColor="transparent"}/>
                  </div>
                )}
                <div>
                  <label style={{fontSize:12,fontWeight:600,color:MT,display:"block",marginBottom:5}}>Notes (optional)</label>
                  <textarea value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})} rows={2} placeholder="Any special instructions..." style={{width:"100%",background:G1,border:"1.5px solid transparent",borderRadius:12,padding:"12px 14px",fontSize:14,resize:"none"}} onFocus={e=>e.target.style.borderColor=P} onBlur={e=>e.target.style.borderColor="transparent"}/>
                </div>
              </div>

              {/* PAYMENT */}
              <div style={{marginBottom:24}}>
                <div style={{fontSize:15,fontWeight:800,marginBottom:12}}>Payment</div>
                <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                  {["MTN MoMo","Telecel","AirtelTigo","Cash"].map(pm=>(
                    <button key={pm} onClick={()=>setPay(pm)} className="tap" style={{padding:"8px 14px",borderRadius:10,border:`1.5px solid ${pay===pm?P:G2}`,background:pay===pm?"rgba(232,23,106,.07)":WH,color:pay===pm?P:MT,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>
                      {pay===pm?"✓ ":""}{pm}
                    </button>
                  ))}
                </div>
              </div>

              {/* TOTAL */}
              <div style={{background:BK,borderRadius:20,padding:"20px"}}>
                <div style={{display:"flex",justifyContent:"space-between",marginBottom:16}}>
                  <span style={{color:"rgba(255,255,255,.55)",fontSize:14}}>Total</span>
                  <span style={{color:WH,fontSize:24,fontWeight:900}}>GH₵{total}</span>
                </div>
                <button onClick={submitOrder} className="tap" style={{width:"100%",padding:"15px",borderRadius:14,border:"none",background:P,color:WH,fontSize:15,fontWeight:800,fontFamily:"inherit",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:10}}>
                  <svg width={20} height={20} viewBox="0 0 24 24" fill="currentColor"><path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z"/></svg>
                  Confirm via WhatsApp
                </button>
              </div>
            </div>
          )}
        </div>
      </>}

      {/* CONTACT */}
      {tab==="contact"&&<>
        <div style={{background:WH,padding:"14px 18px 10px",borderBottom:`1px solid ${G2}`,position:"sticky",top:0,zIndex:50}}>
          <div style={{fontSize:18,fontWeight:900,color:BK}}>Contact</div>
        </div>
        <div style={{flex:1,overflowY:"auto",paddingBottom:80}}>
          <div style={{background:`linear-gradient(135deg,${P} 0%,#b0105a 100%)`,padding:"32px 18px",textAlign:"center"}}>
            <img src={IMGS.logo} alt="Tasty Chef" style={{height:60,objectFit:"contain",marginBottom:10}}/>
            <div style={{color:WH,fontSize:22,fontWeight:900}}>Tasty Chef</div>
            <div style={{color:"rgba(255,255,255,.7)",fontSize:13,marginTop:4}}>For a Tasty Satisfaction</div>
          </div>
          <div style={{padding:"20px 18px"}}>
            {[
              {title:"Opening Hours",icon:"🕐",content:<div><div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><span style={{fontWeight:600}}>Mon – Sun</span><span style={{fontWeight:800,color:P}}>12:00 PM – 9:00 PM</span></div><div style={{fontSize:12,color:MT,marginTop:6}}>Pickup available all operating hours</div></div>},
              {title:"Call Us",icon:"📞",content:<div>{["020 521 8123","055 924 5705","050 260 9335"].map(n=>(
                <a key={n} href={`tel:+233${n.replace(/\s/g,"").slice(1)}`} style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 0",borderBottom:`1px solid ${G1}`,color:BK}}>
                  <span style={{fontWeight:700,fontSize:15}}>{n}</span>
                  <div style={{width:32,height:32,borderRadius:"50%",background:P,display:"flex",alignItems:"center",justifyContent:"center",color:WH,fontSize:16}}>📞</div>
                </a>
              ))}</div>},
              {title:"Follow Us",icon:"📱",content:<div>{[["Instagram","@_tastychef","https://instagram.com/_tastychef","#e1306c"],["TikTok","@_tastychef","https://tiktok.com/@_tastychef",BK],["Facebook","@_tastychef","https://facebook.com","#1877f2"]].map(([pl,h,u,c])=>(
                <a key={pl} href={u} target="_blank" rel="noreferrer" style={{display:"flex",alignItems:"center",justifyContent:"space-between",padding:"10px 0",borderBottom:`1px solid ${G1}`,color:BK}}>
                  <div><div style={{fontWeight:700,fontSize:14}}>{pl}</div><div style={{fontSize:12,color:MT}}>{h}</div></div>
                  <div style={{background:c,color:WH,padding:"5px 14px",borderRadius:100,fontSize:12,fontWeight:700}}>Follow</div>
                </a>
              ))}</div>},
              {title:"We Accept",icon:"💳",content:<div>{["💛 MTN Mobile Money","📱 Telecel Cash","🟥 AirtelTigo Money","💵 Cash on Delivery"].map(pm=>(
                <div key={pm} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 0",borderBottom:`1px solid ${G1}`,fontSize:14,fontWeight:600,color:BK}}>{pm}</div>
              ))}</div>},
            ].map(s=>(
              <div key={s.title} style={{background:G1,borderRadius:20,padding:"18px",marginBottom:14}}>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:14}}>
                  <div style={{width:36,height:36,background:WH,borderRadius:10,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,boxShadow:"0 2px 8px rgba(0,0,0,.07)"}}>{s.icon}</div>
                  <div style={{fontWeight:800,fontSize:15}}>{s.title}</div>
                </div>
                {s.content}
              </div>
            ))}
          </div>
        </div>
      </>}

      {/* BOTTOM NAV */}
      <div style={{position:"fixed",bottom:0,left:"50%",transform:"translateX(-50%)",width:"100%",maxWidth:430,background:WH,borderTop:`1px solid ${G2}`,display:"flex",zIndex:100}}>
        {[
          {id:"home",icon:"🏠",label:"Home"},
          {id:"menu",icon:"🍽️",label:"Menu"},
          {id:"cart",icon:"🛒",label:"Cart",badge:count},
          {id:"contact",icon:"📞",label:"Contact"},
        ].map(n=>(
          <button key={n.id} onClick={()=>setTab(n.id)} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:3,padding:"10px 0 12px",background:"none",border:"none",color:tab===n.id?P:MT,cursor:"pointer",fontFamily:"inherit"}}>
            <div style={{position:"relative",fontSize:22}}>
              {n.icon}
              {n.badge>0&&<div style={{position:"absolute",top:-4,right:-6,background:P,color:WH,borderRadius:"50%",width:17,height:17,fontSize:10,fontWeight:800,display:"flex",alignItems:"center",justifyContent:"center",border:"2px solid white"}}>{n.badge}</div>}
            </div>
            <span style={{fontSize:10,fontWeight:700,letterSpacing:".04em"}}>{n.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}

function Detail({item,onBack,onAdd,cart,chQty,spice,setSpice}){
  const P="#E8176A",BK="#111",G1="#F5F5F7",G2="#E8E8EC",MT="#999",WH="#fff";
  const ci=cart.find(i=>i.id===item.id&&i.spice===spice);
  return(
    <div style={{fontFamily:"'Inter',system-ui,sans-serif",background:WH,maxWidth:430,margin:"0 auto",minHeight:"100vh",display:"flex",flexDirection:"column"}}>
      <style>{`.tap:active{transform:scale(.97);transition:transform 0.1s}`}</style>
      <div style={{position:"relative",flexShrink:0}}>
        <img src={IMGS[item.img]} alt={item.name} style={{width:"100%",height:280,objectFit:"cover",display:"block"}}/>
        <div style={{position:"absolute",inset:0,background:"linear-gradient(to bottom,rgba(0,0,0,.4) 0%,transparent 50%)"}}/>
        <button onClick={onBack} className="tap" style={{position:"absolute",top:16,left:16,width:40,height:40,borderRadius:"50%",background:"rgba(255,255,255,.9)",border:"none",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20}}>←</button>
        {(item.badge||item.pop)&&<div style={{position:"absolute",top:16,right:16,background:P,color:WH,padding:"5px 12px",borderRadius:100,fontSize:11,fontWeight:700}}>{item.badge||"Popular"}</div>}
      </div>
      <div style={{flex:1,padding:"22px 18px",overflowY:"auto"}}>
        <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",gap:12,marginBottom:8}}>
          <div style={{fontSize:22,fontWeight:900,color:BK,lineHeight:1.2}}>{item.name}</div>
          <div style={{fontSize:24,fontWeight:900,color:P,flexShrink:0}}>GH₵{item.price}</div>
        </div>
        <div style={{fontSize:14,color:MT,lineHeight:1.6,marginBottom:24}}>{item.desc}</div>
        <div style={{marginBottom:24}}>
          <div style={{fontSize:12,fontWeight:700,color:BK,textTransform:"uppercase",letterSpacing:".06em",marginBottom:12}}>Spice Level</div>
          <div style={{display:"flex",gap:8}}>
            {[["🟢","Mild"],["🟡","Medium"],["🔴","Hot"],["🔥","Extra Hot"]].map(([e,l])=>(
              <button key={l} onClick={()=>setSpice(l)} className="tap" style={{flex:1,padding:"10px 4px",borderRadius:14,border:`1.5px solid ${spice===l?P:G2}`,background:spice===l?"rgba(232,23,106,.07)":WH,cursor:"pointer",fontFamily:"inherit"}}>
                <div style={{fontSize:18,marginBottom:4}}>{e}</div>
                <div style={{fontSize:11,fontWeight:700,color:spice===l?P:MT}}>{l}</div>
              </button>
            ))}
          </div>
        </div>
        <div style={{display:"flex",gap:8,marginBottom:24}}>
          {[["⏱️","15–25 min"],["🛡️","Fresh daily"],["⭐","Chef's pick"]].map(([ic,l])=>(
            <div key={l} style={{flex:1,background:G1,borderRadius:12,padding:"10px 8px",textAlign:"center"}}>
              <div style={{fontSize:18,marginBottom:4}}>{ic}</div>
              <div style={{fontSize:11,fontWeight:600,color:MT}}>{l}</div>
            </div>
          ))}
        </div>
      </div>
      <div style={{padding:"16px 18px 28px",borderTop:`1px solid ${G2}`,background:WH,flexShrink:0}}>
        {ci?(
          <div style={{display:"flex",alignItems:"center",gap:16}}>
            <button onClick={()=>chQty(item.id,spice,-1)} style={{width:50,height:50,borderRadius:"50%",border:`1.5px solid ${G2}`,background:WH,cursor:"pointer",fontSize:22,fontWeight:700,display:"flex",alignItems:"center",justifyContent:"center"}}>−</button>
            <div style={{flex:1,textAlign:"center"}}>
              <div style={{fontSize:24,fontWeight:900}}>{ci.qty}</div>
              <div style={{fontSize:12,color:MT}}>in cart · GH₵{ci.qty*item.price}</div>
            </div>
            <button onClick={()=>chQty(item.id,spice,1)} style={{width:50,height:50,borderRadius:"50%",background:P,border:"none",cursor:"pointer",color:WH,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22}}>+</button>
          </div>
        ):(
          <button onClick={()=>onAdd(item,spice)} className="tap" style={{width:"100%",padding:"16px",borderRadius:16,border:"none",background:P,color:WH,fontSize:16,fontWeight:800,fontFamily:"inherit",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:10,boxShadow:"0 8px 24px rgba(232,23,106,.3)"}}>
            + Add to Order · GH₵{item.price}
          </button>
        )}
      </div>
    </div>
  );
}
